/**
 * Read ~/.mycelium/config.json (or fall back to config.toml) for JS/TS consumers.
 *
 * Phase 2 of unified config: config.json is a JSON snapshot generated by the
 * Python CLI every time config.toml is saved.  This eliminates the hand-rolled
 * TOML parser and gives JS hooks access to all config sections, not just [server].
 *
 * Bundled with the OpenClaw plugin; hooks import via
 * ../../extensions/mycelium/read-mycelium-config.js.
 */
import fs from "node:fs";
import { homedir } from "node:os";
import { join } from "node:path";

/**
 * Full config object shape (mirrors MyceliumConfig in Python).
 * @typedef {{
 *   server?: { api_url?: string; workspace_id?: string; mas_id?: string };
 *   llm?: { model?: string; api_key?: string; base_url?: string };
 *   runtime?: { db_port?: number; backend_port?: number; data_dir?: string; workspace_id?: string };
 *   identity?: { name?: string; machine_id?: string; autonomous?: boolean };
 *   rooms?: { active?: string };
 * }} MyceliumConfigSnapshot
 */

/** @type {MyceliumConfigSnapshot | null} */
let _cache = null;

/**
 * Read the full config snapshot.  Prefers config.json (generated by
 * ``mycelium config save``); falls back to a lightweight TOML parse of
 * config.toml [server] section for backwards compatibility.
 *
 * @returns {MyceliumConfigSnapshot}
 */
export function readMyceliumConfig() {
  if (_cache) return _cache;

  const configDir = join(homedir(), ".mycelium");

  // Prefer the JSON snapshot (generated by Python CLI on every save)
  const jsonPath = join(configDir, "config.json");
  try {
    const text = fs.readFileSync(jsonPath, "utf-8");
    _cache = JSON.parse(text);
    return _cache;
  } catch {
    // JSON snapshot not available — fall back to TOML parse
  }

  // Backwards-compatible: parse config.toml [server] section
  const tomlPath = join(configDir, "config.toml");
  try {
    const text = fs.readFileSync(tomlPath, "utf-8");
    _cache = { server: parseServerSection(text) };
    return _cache;
  } catch {
    return {};
  }
}

/**
 * Convenience wrapper — returns just the [server] section.
 * Backwards-compatible with the old readMyceliumServerFromToml() API.
 *
 * @returns {{ api_url?: string; workspace_id?: string; mas_id?: string }}
 */
export function readMyceliumServerFromToml() {
  const cfg = readMyceliumConfig();
  return cfg.server ?? {};
}

/**
 * Invalidate the cached config so the next read re-reads from disk.
 */
export function clearConfigCache() {
  _cache = null;
}

/**
 * Legacy TOML [server] parser — kept as fallback for installs that haven't
 * run ``mycelium config apply`` yet.
 *
 * @param {string} text
 * @returns {{ api_url?: string; workspace_id?: string; mas_id?: string }}
 */
export function parseServerSection(text) {
  /** @type {Record<string, string>} */
  const keys = {};
  let inServer = false;
  for (const line of text.split(/\r?\n/)) {
    const trimmed = line.trim();
    if (!trimmed || trimmed.startsWith("#")) continue;
    if (/^\[server\]\s*$/i.test(trimmed)) {
      inServer = true;
      continue;
    }
    if (trimmed.startsWith("[") && trimmed.endsWith("]")) {
      inServer = false;
      continue;
    }
    if (!inServer) continue;
    const eq = trimmed.indexOf("=");
    if (eq <= 0) continue;
    const key = trimmed.slice(0, eq).trim();
    let val = trimmed.slice(eq + 1).trim();
    if (
      (val.startsWith('"') && val.endsWith('"')) ||
      (val.startsWith("'") && val.endsWith("'"))
    ) {
      val = val.slice(1, -1).replace(/\\"/g, '"');
    }
    keys[key] = val;
  }
  return {
    api_url: keys.api_url,
    workspace_id: keys.workspace_id,
    mas_id: keys.mas_id,
  };
}
